var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"WARDER_NPC_NEW_NULL","text":{"KOREA":"지시하신 서류업무 전부 끝냈습니다.","JPN":"指示された書類業務はすべて終わらせました。","ENG":"I've finished all the paperwork as you instructed.","TWN":"您指示的文書工作已經全部完成。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"WARDER_NPC_OLD_NULL","text":{"KOREA":"그래, 고생했어. 곧 근무 교대할 준비해.","JPN":"ああ、ご苦労様。交代準備をしていいぞ。","ENG":"Well done. Someone will be here shortly to take your shift.","TWN":"好，辛苦了。準備換班吧。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"WARDER_NPC_NEW_NULL","text":{"KOREA":"......저기, 그런데 제 3호 독방에 있는 저 죄수는 뭡니까?","JPN":"あの……ところで第3号独房にいる囚人は何者ですか？","ENG":"By the way, who's the prisoner in the third solitary confinement cell?","TWN":"……那個，3號單人房的罪犯是誰？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"WARDER_NPC_NEW_NULL","text":{"KOREA":"독방은 면회 금지일 텐데 사람들도 매일 찾아오네요.","JPN":"独房は面会禁止なのに、毎日誰かしら訪ねてくるのが不思議でして。","ENG":"I thought inmates in solitary weren't allowed visitors, but he's got them every day.","TWN":"單人房明明禁止會面，卻每天都有人來看他。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"WARDER_NPC_NEW_NULL","text":{"KOREA":"거기다가 죄수복도 안 입고 있고......","JPN":"それに、受刑者用の服も着ていないですし……","ENG":"Plus, he's not even in uniform...","TWN":"而且他也沒穿囚衣……"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"WARDER_NPC_OLD_NULL","text":{"KOREA":"......알면 다쳐.","JPN":"……知らなくていいことだってある。","ENG":"Trust me, the less you know, the better.","TWN":"……別想知道太多。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"WARDER_NPC_OLD_NULL","text":{"KOREA":"괜히 쓸데없는 데 관심 가지지 말고 모른 척 해.","JPN":"興味を持つ必要はない、知らないフリをしろ。","ENG":"Stop getting nosy and just pretend you didn't see anything.","TWN":"別多管閒事，假裝什麼都不知道。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"WARDER_NPC_OLD_NULL","text":{"KOREA":"다 널 위해 하는 말이야.","JPN":"これは君のための忠告だ。","ENG":"This is all for your sake.","TWN":"這都是為你好。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"WARDER_NPC_OLD_NULL","text":{"KOREA":"소장님 지시기도 하니까 괜히 문제 일으키지 말고 입 단속 잘하라고.","JPN":"所長の指示でもあるから、余計なトラブルは控えろ。あと、君も含めて周りの口止めもな。","ENG":"The warden specifically demanded this arrangement, so try to keep your mouth shut.","TWN":"而且這也是所長大人的指示，不要惹事，管好自己的嘴。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"WARDER_NPC_NEW_NULL","text":{"KOREA":"네......?","JPN":"はい……？","ENG":"Sir?","TWN":"什麼……？"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"......다시 말해 봐.","JPN":"……もう一度言ってみろ。","ENG":"... Let me hear that again.","TWN":"……再說一遍。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CRIMINAL_NPC_INVADER_NULL","text":{"KOREA":"면목 없습니다, 보스.","JPN":"申し訳ありません、ボス。","ENG":"Sorry, boss.","TWN":"對不起，老闆。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"누가 사과하라고 했나? 다시 말해 보라고.","JPN":"謝れとは言ってない。もう一度言ってみろ。","ENG":"I didn't ask for an apology. Tell me what happened again.","TWN":"誰讓你道歉了？我說再說一遍。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CRIMINAL_NPC_INVADER_NULL","text":{"KOREA":"......저희가 도착했을 때는 이미 치명상을 입은 상태였습니다.","JPN":"……私たちが到着した時は、すでに致命傷を負った状態でした。","ENG":"He was already critically wounded by the time we got to him.","TWN":"……我們抵達時，他已經受了致命傷。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"그러니까...... 도현이가 죽었다는 말이야?","JPN":"だから……リョウが死んだと？","ENG":"Are you telling me... Dohyun is dead?","TWN":"也就是說……道賢死了？"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CRIMINAL_NPC_INVADER_NULL","text":{"KOREA":"네, 최선을 다했지만 어쩔 수 없이......","JPN":"はい、最善を尽くしましたが惜しくも……","ENG":"We tried our best, but I'm afraid so...","TWN":"是，我們盡全力搶救了，可是……"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CRIMINAL_NPC_INVADER_NULL","text":{"KOREA":"부디 용서해 주십시오.","JPN":"どうかお許しください。","ENG":"Please forgive us.","TWN":"請您原諒。"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"짜식.","JPN":"そんなにビビるなよ。","ENG":"Relax.","TWN":"你這小子，"},"stage":{"bg":"PRISON_NIGHT","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};